import React from "react";
import "./Home.css";
import Grid from "@material-ui/core/Grid";
import Switch from "@material-ui/core/Switch";
import Slider from "@material-ui/core/Slider";
import Container from "@material-ui/core/Container";

class Home extends React.Component {
  constructor(props) {
    super(props);
    this.state = { checked: this.props.data['STATE_STATUS'],
    data: this.props.data };
    this.handleChange = this.handleChange.bind(this);
  }

  handleChange (checked){
    console.log(this.state.data['STATE_STATUS'])
    this.setState({ checked });
  }

  checkStatus = (e) => {
    console.log(e);
  };

  render() {
    return (
      <div className="Home">
        <Container maxWidth="xs">
          <Grid container spacing={1}>
            <Grid item xs={6}>
              Status
              {this.state.checked}
            </Grid>
            <Grid item xs={6}>
              <Switch
                name="checkedStatus"
                color="primary"
                checked={this.state.checked}
                onChange={(event) => this.handleChange(event.currentTarget.checked)}
              />
            </Grid>
            <Grid item xs={12}>
              <hr></hr>
            </Grid>
            <Grid item xs={6}>
              Light Sensor
            </Grid>
            <Grid item xs={6}>
              <Switch name="checkedB" color="primary" />
            </Grid>
            <Grid item xs={12}>
              Brightness
            </Grid>
            <Grid item xs={12}>
              <Slider aria-labelledby="continuous-slider" />
            </Grid>
            <Grid item xs={12}>
              <hr></hr>
            </Grid>
            <Grid item xs={12}>
              Red
            </Grid>
            <Grid item xs={12}>
              <Slider aria-labelledby="continuous-slider" />
            </Grid>
            <Grid item xs={12}>
              Green
            </Grid>
            <Grid item xs={12}>
              <Slider aria-labelledby="continuous-slider" />
            </Grid>
            <Grid item xs={12}>
              Blue
            </Grid>
            <Grid item xs={12}>
              <Slider aria-labelledby="continuous-slider" />
            </Grid>
          </Grid>
        </Container>
      </div>
    );
  }
}

export default Home;
